def generate_polyominoes(n):
    def can_place(polyomino, x, y, grid):
        for dx, dy in polyomino:
            if not (0 <= x + dx < len(grid) and 0 <= y + dy < len(grid) and grid[x + dx][y + dy] == 0):
                return False
        return True

    def place(polyomino, x, y, grid, value):
        for dx, dy in polyomino:
            grid[x + dx][y + dy] = value

    def find_polyominoes(current_polyomino, grid, x, y):
        if len(current_polyomino) == n:
            unique_polyominoes.add(tuple(sorted(current_polyomino)))
            return

        for dx, dy in [(0, 1), (1, 0), (0, -1), (-1, 0)]:
            new_x, new_y = x + dx, y + dy
            if can_place(current_polyomino, new_x, new_y, grid):
                place(current_polyomino, new_x, new_y, grid, 1)
                find_polyominoes(current_polyomino + [(dx, dy)], grid, new_x, new_y)
                place(current_polyomino, new_x, new_y, grid, 0)

    unique_polyominoes = set()
    grid = [[0] * (n + 1) for _ in range(n + 1)]
    find_polyominoes([(0, 0)], grid, 0, 0)

    return unique_polyominoes

def generate_all_polyominoes(max_n):
    all_polyominoes = {}
    for n in range(1, max_n + 1):
        all_polyominoes[n] = generate_polyominoes(n)
    return all_polyominoes

